import { revalidateTag } from "next/cache";
import { getAllProducts } from "../lib/db";

function formatPrice(value) {
  return new Intl.NumberFormat("en-US", {
    style: "currency",
    currency: "USD",
    maximumFractionDigits: 0,
  }).format(value);
}

export default async function Page() {
  const products = await getAllProducts();

  async function syncCatalog() {
    "use server";
    revalidateTag("products", "max");
  }

  const totalInventory = products.reduce((sum, product) => sum + product.inventory, 0);
  const lowStockCount = products.filter((product) => product.availability === "Low stock").length;

  return (
    <main
      style={{
        minHeight: "100vh",
        padding: "48px 24px",
        background:
          "radial-gradient(circle at top left, rgba(245, 158, 11, 0.16), transparent 32%), linear-gradient(180deg, #0f172a 0%, #111827 100%)",
        color: "#e5e7eb",
        fontFamily:
          "Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, sans-serif",
      }}
    >
      <section
        style={{
          maxWidth: 1120,
          margin: "0 auto",
          display: "grid",
          gap: 24,
        }}
      >
        <header
          style={{
            display: "flex",
            flexWrap: "wrap",
            justifyContent: "space-between",
            gap: 16,
            alignItems: "end",
          }}
        >
          <div>
            <p style={{ margin: 0, color: "#fbbf24", textTransform: "uppercase", letterSpacing: 1.6 }}>
              Catalog Admin
            </p>
            <h1 style={{ margin: "8px 0 0", fontSize: 44, lineHeight: 1.05 }}>Product catalog</h1>
            <p style={{ margin: "12px 0 0", color: "#94a3b8", maxWidth: 640 }}>
              Browsing is fully cached for day-to-day use. Sync only marks the catalog stale so
              the next read refreshes in the background across every view that uses the same tag.
            </p>
          </div>

          <form action={syncCatalog}>
            <button
              type="submit"
              style={{
                border: "1px solid rgba(251, 191, 36, 0.4)",
                background: "linear-gradient(135deg, #f59e0b, #d97706)",
                color: "#111827",
                fontWeight: 700,
                padding: "14px 18px",
                borderRadius: 14,
                cursor: "pointer",
                boxShadow: "0 16px 32px rgba(245, 158, 11, 0.22)",
              }}
            >
              Sync latest catalog
            </button>
          </form>
        </header>

        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fit, minmax(180px, 1fr))",
            gap: 16,
          }}
        >
          {[
            { label: "Products", value: products.length },
            { label: "Total inventory", value: totalInventory },
            { label: "Low stock", value: lowStockCount },
          ].map((item) => (
            <article
              key={item.label}
              style={{
                background: "rgba(15, 23, 42, 0.72)",
                border: "1px solid rgba(148, 163, 184, 0.16)",
                borderRadius: 20,
                padding: 20,
                backdropFilter: "blur(16px)",
              }}
            >
              <p style={{ margin: 0, color: "#94a3b8" }}>{item.label}</p>
              <p style={{ margin: "10px 0 0", fontSize: 34, fontWeight: 700 }}>{item.value}</p>
            </article>
          ))}
        </div>

        <section
          style={{
            background: "rgba(15, 23, 42, 0.82)",
            border: "1px solid rgba(148, 163, 184, 0.16)",
            borderRadius: 24,
            overflow: "hidden",
            backdropFilter: "blur(18px)",
          }}
        >
          <div style={{ padding: 20, borderBottom: "1px solid rgba(148, 163, 184, 0.16)" }}>
            <h2 style={{ margin: 0, fontSize: 20 }}>Catalog snapshot</h2>
            <p style={{ margin: "8px 0 0", color: "#94a3b8" }}>
              Cached with the <code>products</code> tag. Reads stay fast until a sync marks the
              catalog stale.
            </p>
          </div>

          <div style={{ overflowX: "auto" }}>
            <table style={{ width: "100%", borderCollapse: "collapse" }}>
              <thead>
                <tr style={{ textAlign: "left", color: "#cbd5e1" }}>
                  {["SKU", "Product", "Price", "Inventory", "Availability"].map((head) => (
                    <th
                      key={head}
                      style={{
                        padding: "16px 20px",
                        fontSize: 12,
                        letterSpacing: 1,
                        textTransform: "uppercase",
                        borderBottom: "1px solid rgba(148, 163, 184, 0.16)",
                      }}
                    >
                      {head}
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {products.map((product) => (
                  <tr key={product.id} style={{ color: "#e5e7eb" }}>
                    <td style={{ padding: "16px 20px", borderBottom: "1px solid rgba(148, 163, 184, 0.08)" }}>
                      #{product.id}
                    </td>
                    <td style={{ padding: "16px 20px", borderBottom: "1px solid rgba(148, 163, 184, 0.08)" }}>
                      {product.name}
                    </td>
                    <td style={{ padding: "16px 20px", borderBottom: "1px solid rgba(148, 163, 184, 0.08)" }}>
                      {formatPrice(product.price)}
                    </td>
                    <td style={{ padding: "16px 20px", borderBottom: "1px solid rgba(148, 163, 184, 0.08)" }}>
                      {product.inventory}
                    </td>
                    <td style={{ padding: "16px 20px", borderBottom: "1px solid rgba(148, 163, 184, 0.08)" }}>
                      {product.availability}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>
      </section>
    </main>
  );
}

